#include <vector>

bool solve(std::vector<long long> nums) {
    int n = nums.size();
    for (int p = 1; p <= n - 2; ++p) {
        bool first_incr = true;
        for (int i = 0; i < p; ++i) {
            if (nums[i] >= nums[i + 1]) {
                first_incr = false;
                break;
            }
        }
        if (!first_incr) continue;

        int q = p;
        while (q + 1 < n && nums[q + 1] < nums[q]) {
            q++;
        }

        if (q < p + 1) continue;

        bool third_incr = true;
        for (int i = q; i < n - 1; ++i) {
            if (nums[i] >= nums[i + 1]) {
                third_incr = false;
                break;
            }
        }

        if (third_incr) return true;
    }
    return false;
}
